1	//! Indexing operations for DenseArray.
2	
3	use crate::dense::DenseArray;
4	use crate::error::ArrayError;
5	
6	impl DenseArray {
7	    /// Number of dimensions (delegates to shape).
8	    #[must_use]
9	    pub fn rank(&self) -> usize {
10	        self.shape().rank()
11	    }
12	
13	    /// Total element count (delegates to shape).
14	    #[must_use]
15	    pub fn elem_count(&self) -> usize {
16	        self.shape().elem_count()
17	    }
18	
19	    /// Borrow the optional per-axis label slice.
20	    ///
21	    /// `None` means every axis is positional (the common case).
22	    /// `Some(slice)` has one entry per axis, with inner `None` for
23	    /// positional axes in a partially-labeled shape. Lives here
24	    /// rather than in `dense.rs` to group the short shape-metadata
25	    /// accessors (`rank`, `elem_count`, `labels`) together and keep
26	    /// `dense.rs` at its 7-function sw-checklist budget.
27	    #[must_use]
28	    pub fn labels(&self) -> Option<&[Option<String>]> {
29	        self.labels.as_deref()
30	    }
31	
32	    /// Get a reference to the element at multi-dimensional index.
33	    pub fn get(&self, index: &[usize]) -> Result<&f64, ArrayError> {
34	        let offset = self.validate_index(index)?;
35	        Ok(&self.data()[offset])
36	    }
37	
38	    /// Set the element at multi-dimensional index.
39	    pub fn set(&mut self, index: &[usize], value: f64) -> Result<(), ArrayError> {
40	        let offset = self.validate_index(index)?;
41	        self.data[offset] = value;
42	        Ok(())
43	    }
44	
45	    /// Validate index and return flat offset.
46	    fn validate_index(&self, index: &[usize]) -> Result<usize, ArrayError> {
47	        if self.elem_count() == 0 {
48	            return Err(ArrayError::EmptyArray);
49	        }
50	        let dims = self.shape().dims();
51	        if index.len() != dims.len() {
52	            return Err(ArrayError::RankMismatch {
53	                expected: dims.len(),
54	                got: index.len(),
55	            });
56	        }
57	        let mut offset = 0;
58	        let mut stride = self.elem_count();
59	        for (axis, (&idx, &dim)) in index.iter().zip(dims.iter()).enumerate() {
60	            if idx >= dim {
61	                return Err(ArrayError::IndexOutOfBounds {
62	                    axis,
63	                    index: idx,
64	                    size: dim,
65	                });
66	            }
67	            stride /= dim;
68	            offset += idx * stride;
69	        }
70	        Ok(offset)
71	    }
72	}
73

