1	//! Parser: transforms token stream into AST.
2	
3	use mlpl_core::Span;
4	
5	use crate::ast::{BinOpKind, Expr, TensorCtorKind};
6	use crate::error::ParseError;
7	use crate::token::{Token, TokenKind};
8	
9	/// Parse a token stream into a list of expression statements.
10	pub fn parse(tokens: &[Token]) -> Result<Vec<Expr>, ParseError> {
11	    let mut p = Parser::new(tokens);
12	    let mut stmts = Vec::new();
13	    p.skip_sep();
14	    while p.pos < p.tokens.len() && p.tokens[p.pos].kind != TokenKind::Eof {
15	        stmts.push(p.parse_statement()?);
16	        p.skip_sep();
17	    }
18	    Ok(stmts)
19	}
20	
21	pub(crate) struct Parser<'a> {
22	    pub(crate) tokens: &'a [Token],
23	    pub(crate) pos: usize,
24	}
25	
26	impl<'a> Parser<'a> {
27	    pub(crate) fn new(tokens: &'a [Token]) -> Self {
28	        Self { tokens, pos: 0 }
29	    }
30	
31	    /// Parse a single statement (assignment, repeat, or expression).
32	    fn parse_statement(&mut self) -> Result<Expr, ParseError> {
33	        if self.tokens[self.pos].kind == TokenKind::Repeat {
34	            return self.parse_repeat(false);
35	        }
36	        if self.tokens[self.pos].kind == TokenKind::Train {
37	            return self.parse_repeat(true);
38	        }
39	        if matches!(self.tokens[self.pos].kind, TokenKind::Ident(_))
40	            && self
41	                .tokens
42	                .get(self.pos + 1)
43	                .is_some_and(|t| t.kind == TokenKind::Equals)
44	        {
45	            let name_tok = &self.tokens[self.pos];
46	            let name = match &name_tok.kind {
47	                TokenKind::Ident(n) => n.clone(),
48	                _ => unreachable!(),
49	            };
50	            let start = name_tok.span;
51	            self.pos += 2;
52	            let value = self.parse_expr(0)?;
53	            let span = Span::new(start.start, value.span().end);
54	            return Ok(Expr::Assign {
55	                name,
56	                value: Box::new(value),
57	                span,
58	            });
59	        }
60	        self.parse_expr(0)
61	    }
62	
63	    /// Parse an expression with precedence climbing (min_prec=0 for full expr).
64	    pub(crate) fn parse_expr(&mut self, min_prec: u8) -> Result<Expr, ParseError> {
65	        let mut lhs = self.parse_atom()?;
66	        loop {
67	            let Some((op, prec)) = self.tokens.get(self.pos).and_then(|t| match t.kind {
68	                TokenKind::Plus => Some((BinOpKind::Add, 1u8)),
69	                TokenKind::Minus => Some((BinOpKind::Sub, 1)),
70	                TokenKind::Star => Some((BinOpKind::Mul, 2)),
71	                TokenKind::Slash => Some((BinOpKind::Div, 2)),
72	                _ => None,
73	            }) else {
74	                break;
75	            };
76	            if prec < min_prec {
77	                break;
78	            }
79	            self.pos += 1;
80	            let rhs = self.parse_expr(prec + 1)?;
81	            let span = Span::new(lhs.span().start, rhs.span().end);
82	            lhs = Expr::BinOp {
83	                op,
84	                lhs: Box::new(lhs),
85	                rhs: Box::new(rhs),
86	                span,
87	            };
88	        }
89	        Ok(lhs)
90	    }
91	
92	    pub(crate) fn parse_atom(&mut self) -> Result<Expr, ParseError> {
93	        let tok = &self.tokens[self.pos];
94	        match &tok.kind {
95	            TokenKind::Minus => {
96	                let start = tok.span;
97	                self.pos += 1;
98	                let operand = self.parse_atom()?;
99	                let span = Span::new(start.start, operand.span().end);
100	                Ok(Expr::UnaryNeg {
101	                    operand: Box::new(operand),
102	                    span,
103	                })
104	            }
105	            TokenKind::IntLit(n) => {
106	                let e = Expr::IntLit(*n, tok.span);
107	                self.pos += 1;
108	                Ok(e)
109	            }
110	            TokenKind::FloatLit(f) => {
111	                let e = Expr::FloatLit(*f, tok.span);
112	                self.pos += 1;
113	                Ok(e)
114	            }
115	            TokenKind::StrLit(s) => {
116	                let e = Expr::StrLit(s.clone(), tok.span);
117	                self.pos += 1;
118	                Ok(e)
119	            }
120	            TokenKind::Ident(name) => {
121	                let name = name.clone();
122	                let start = tok.span;
123	                self.pos += 1;
124	                // Tensor constructor: `param[...]` or `tensor[...]`
125	                if self.is(TokenKind::LBracket) {
126	                    let ctor_kind = match name.as_str() {
127	                        "param" => Some(TensorCtorKind::Param),
128	                        "tensor" => Some(TensorCtorKind::Tensor),
129	                        _ => None,
130	                    };
131	                    if let Some(kind) = ctor_kind {
132	                        return self.parse_tensor_ctor(kind, start);
133	                    }
134	                }
135	                // Function call: ident '('
136	                if self.is(TokenKind::LParen) {
137	                    self.pos += 1; // skip '('
138	                    let mut args = Vec::new();
139	                    if !self.is(TokenKind::RParen) {
140	                        args.push(self.parse_expr(0)?);
141	                        while self.is(TokenKind::Comma) {
142	                            self.pos += 1;
143	                            args.push(self.parse_expr(0)?);
144	                        }
145	                    }
146	                    if !self.is(TokenKind::RParen) {
147	                        return Err(ParseError::UnclosedDelimiter {
148	                            open: "(".into(),
149	                            span: start,
150	                        });
151	                    }
152	                    let end = self.tokens[self.pos].span;
153	                    self.pos += 1;
154	                    Ok(Expr::FnCall {
155	                        name,
156	                        args,
157	                        span: Span::new(start.start, end.end),
158	                    })
159	                } else {
160	                    Ok(Expr::Ident(name, start))
161	                }
162	            }
163	            TokenKind::LBracket => self.parse_array_lit(),
164	            TokenKind::LParen => {
165	                let open = tok.span;
166	                self.pos += 1;
167	                let expr = self.parse_expr(0)?;
168	                if !self.is(TokenKind::RParen) {
169	                    return Err(ParseError::UnclosedDelimiter {
170	                        open: "(".into(),
171	                        span: open,
172	                    });
173	                }
174	                self.pos += 1;
175	                Ok(expr)
176	            }
177	            _ => Err(ParseError::UnexpectedToken {
178	                found: describe_kind(&tok.kind),
179	                span: tok.span,
180	            }),
181	        }
182	    }
183	
184	    fn parse_tensor_ctor(&mut self, kind: TensorCtorKind, start: Span) -> Result<Expr, ParseError> {
185	        let open_span = self.tokens[self.pos].span;
186	        self.pos += 1; // skip '['
187	        let mut shape = Vec::new();
188	        if !self.is(TokenKind::RBracket) {
189	            shape.push(self.parse_expr(0)?);
190	            while self.is(TokenKind::Comma) {
191	                self.pos += 1;
192	                shape.push(self.parse_expr(0)?);
193	            }
194	        }
195	        if !self.is(TokenKind::RBracket) {
196	            return Err(ParseError::UnclosedDelimiter {
197	                open: "[".into(),
198	                span: open_span,
199	            });
200	        }
201	        let close_span = self.tokens[self.pos].span;
202	        self.pos += 1;
203	        Ok(Expr::TensorCtor {
204	            kind,
205	            shape,
206	            span: Span::new(start.start, close_span.end),
207	        })
208	    }
209	
210	    fn parse_array_lit(&mut self) -> Result<Expr, ParseError> {
211	        let open_span = self.tokens[self.pos].span;
212	        self.pos += 1;
213	        let mut elems = Vec::new();
214	        if !self.is(TokenKind::RBracket) {
215	            elems.push(self.parse_expr(0)?);
216	            while self.is(TokenKind::Comma) {
217	                self.pos += 1;
218	                elems.push(self.parse_expr(0)?);
219	            }
220	        }
221	        if !self.is(TokenKind::RBracket) {
222	            return Err(ParseError::UnclosedDelimiter {
223	                open: "[".into(),
224	                span: open_span,
225	            });
226	        }
227	        let close_span = self.tokens[self.pos].span;
228	        self.pos += 1;
229	        Ok(Expr::ArrayLit(
230	            elems,
231	            Span::new(open_span.start, close_span.end),
232	        ))
233	    }
234	
235	    fn parse_repeat(&mut self, is_train: bool) -> Result<Expr, ParseError> {
236	        let start = self.tokens[self.pos].span;
237	        self.pos += 1; // skip 'repeat' or 'train'
238	        let count = self.parse_expr(0)?;
239	        if !self.is(TokenKind::LBrace) {
240	            return Err(ParseError::UnexpectedToken {
241	                found: describe_kind(&self.tokens[self.pos].kind),
242	                span: self.tokens[self.pos].span,
243	            });
244	        }
245	        let body = self.parse_brace_body()?;
246	        let end = self.tokens[self.pos - 1].span;
247	        let span = Span::new(start.start, end.end);
248	        let count = Box::new(count);
249	        Ok(if is_train {
250	            Expr::Train { count, body, span }
251	        } else {
252	            Expr::Repeat { count, body, span }
253	        })
254	    }
255	
256	    fn parse_brace_body(&mut self) -> Result<Vec<Expr>, ParseError> {
257	        let open = self.tokens[self.pos].span;
258	        self.pos += 1; // skip '{'
259	        self.skip_sep();
260	        let mut body = Vec::new();
261	        while self.pos < self.tokens.len()
262	            && !self.is(TokenKind::RBrace)
263	            && self.tokens[self.pos].kind != TokenKind::Eof
264	        {
265	            body.push(self.parse_statement()?);
266	            self.skip_sep();
267	        }
268	        if !self.is(TokenKind::RBrace) {
269	            return Err(ParseError::UnclosedDelimiter {
270	                open: "{".into(),
271	                span: open,
272	            });
273	        }
274	        self.pos += 1; // skip '}'
275	        Ok(body)
276	    }
277	
278	    pub(crate) fn is(&self, kind: TokenKind) -> bool {
279	        self.pos < self.tokens.len()
280	            && std::mem::discriminant(&self.tokens[self.pos].kind) == std::mem::discriminant(&kind)
281	    }
282	
283	    pub(crate) fn skip_sep(&mut self) {
284	        while self.pos < self.tokens.len()
285	            && matches!(
286	                self.tokens[self.pos].kind,
287	                TokenKind::Newline | TokenKind::Semicolon
288	            )
289	        {
290	            self.pos += 1;
291	        }
292	    }
