/// Parse `name : [axis1, axis2, ...] = value` and desugar to
/// `Assign { name, value: FnCall("label", [value, ArrayLit([StrLit(a1), ...])]) }`.
/// Saga 11.5 Phase 2. The bracket list holds bare identifiers; each
/// is captured as a string label. An empty list `[]` is legal and
/// means "scalar with no axes".
fn parse_annotated_assign(&mut self) -> Result<Expr, ParseError> {
    let name_tok = &self.tokens[self.pos];
    let name = match &name_tok.kind {
        TokenKind::Ident(n) => n.clone(),
        _ => unreachable!(),
    };
    let start = name_tok.span;
    self.pos += 2; // skip name and colon
    if !self.is(TokenKind::LBracket) {
        return Err(ParseError::UnexpectedToken {
            found: describe_kind(&self.tokens[self.pos].kind),
            span: self.tokens[self.pos].span,
        });
    }
    let bracket_start = self.tokens[self.pos].span;
    self.pos += 1; // skip '['
    let mut label_exprs: Vec<Expr> = Vec::new();
    if !self.is(TokenKind::RBracket) {
        label_exprs.push(self.parse_axis_label()?);
        while self.is(TokenKind::Comma) {
            self.pos += 1;
            label_exprs.push(self.parse_axis_label()?);
        }
    }
    if !self.is(TokenKind::RBracket) {
        return Err(ParseError::UnclosedDelimiter {
            open: "[".into(),
            span: bracket_start,
        });
    }
    let bracket_end = self.tokens[self.pos].span;
    self.pos += 1; // skip ']'
    if !self.is(TokenKind::Equals) {
        return Err(ParseError::UnexpectedToken {
            found: describe_kind(&self.tokens[self.pos].kind),
            span: self.tokens[self.pos].span,
        });
    }
    self.pos += 1; // skip '='
    let value = self.parse_expr(0)?;
    let value_span = value.span();
    let call_span = Span::new(bracket_start.start, value_span.end);
    let labels_arr_span = Span::new(bracket_start.start, bracket_end.end);
    let call = Expr::FnCall {
        name: "label".into(),
        args: vec![value, Expr::ArrayLit(label_exprs, labels_arr_span)],
        span: call_span,
    };
    Ok(Expr::Assign {
        name,
        value: Box::new(call),
        span: Span::new(start.start, value_span.end),
    })
}

fn parse_axis_label(&mut self) -> Result<Expr, ParseError> {
    let tok = &self.tokens[self.pos];
    match &tok.kind {
        TokenKind::Ident(n) => {
            let e = Expr::StrLit(n.clone(), tok.span);
            self.pos += 1;
            Ok(e)
        }
        _ => Err(ParseError::UnexpectedToken {
            found: describe_kind(&tok.kind),
            span: tok.span,
        }),
    }
}

