26	impl<'a> Parser<'a> {
27	    /// Parse a single statement (assignment, repeat, or expression).
28	    fn parse_statement(&mut self) -> Result<Expr, ParseError> {
29	        if self.tokens[self.pos].kind == TokenKind::Repeat {
30	            return self.parse_repeat(false);
31	        }
32	        if self.tokens[self.pos].kind == TokenKind::Train {
33	            return self.parse_repeat(true);
34	        }
35	        if matches!(self.tokens[self.pos].kind, TokenKind::Ident(_))
36	            && self
37	                .tokens
38	                .get(self.pos + 1)
39	                .is_some_and(|t| t.kind == TokenKind::Equals)
40	        {
41	            let name_tok = &self.tokens[self.pos];
42	            let name = match &name_tok.kind {
43	                TokenKind::Ident(n) => n.clone(),
44	                _ => unreachable!(),
45	            };
46	            let start = name_tok.span;
47	            self.pos += 2;
48	            let value = self.parse_expr(0)?;
49	            let span = Span::new(start.start, value.span().end);
50	            return Ok(Expr::Assign {
51	                name,
52	                value: Box::new(value),
53	                span,
54	            });
55	        }
56	        if matches!(self.tokens[self.pos].kind, TokenKind::Ident(_))
57	            && self
58	                .tokens
59	                .get(self.pos + 1)
60	                .is_some_and(|t| t.kind == TokenKind::Colon)
61	        {
62	            return self.parse_annotated_assign();
63	        }
64	        self.parse_expr(0)
