67	    /// Parse `name : [axis1, axis2, ...] = value` and desugar to
68	    /// `Assign { name, value: FnCall("label", [value, ArrayLit([StrLit(a1), ...])]) }`.
69	    /// Saga 11.5 Phase 2. The bracket list holds bare identifiers; each
70	    /// is captured as a string label. An empty list `[]` is legal and
71	    /// means "scalar with no axes".
72	    fn parse_annotated_assign(&mut self) -> Result<Expr, ParseError> {
73	        let start = self.tokens[self.pos].span;
74	        let TokenKind::Ident(n) = &self.tokens[self.pos].kind else {
75	            unreachable!()
76	        };
77	        let name = n.clone();
78	        self.pos += 2; // skip name and ':'
79	        let br_start = self.expect(&TokenKind::LBracket)?;
80	        let mut labels: Vec<Expr> = Vec::new();
81	        while !self.is(TokenKind::RBracket) {
82	            let tok = &self.tokens[self.pos];
83	            let TokenKind::Ident(a) = &tok.kind else {
84	                return Err(ParseError::UnexpectedToken {
85	                    found: describe_kind(&tok.kind),
86	                    span: tok.span,
87	                });
88	            };
89	            labels.push(Expr::StrLit(a.clone(), tok.span));
90	            self.pos += 1;
91	            if self.is(TokenKind::Comma) {
92	                self.pos += 1;
93	            } else {
94	                break;
95	            }
96	        }
97	        let br_end = self.expect(&TokenKind::RBracket)?;
98	        self.expect(&TokenKind::Equals)?;
99	        let value = self.parse_expr(0)?;
100	        let value_span = value.span();
101	        let call = Expr::FnCall {
102	            name: "label".into(),
103	            args: vec![
104	                value,
105	                Expr::ArrayLit(labels, Span::new(br_start.start, br_end.end)),
106	            ],
107	            span: Span::new(br_start.start, value_span.end),
108	        };
109	        Ok(Expr::Assign {
110	            name,
111	            value: Box::new(call),
112	            span: Span::new(start.start, value_span.end),
113	        })
114	    }
