116	    /// Consume a token of the given kind or return `UnexpectedToken`.
117	    /// Returns the consumed token's span on success.
118	    fn expect(&mut self, kind: &TokenKind) -> Result<Span, ParseError> {
119	        if std::mem::discriminant(&self.tokens[self.pos].kind) == std::mem::discriminant(kind) {
120	            let span = self.tokens[self.pos].span;
121	            self.pos += 1;
122	            Ok(span)
123	        } else {
124	            Err(ParseError::UnexpectedToken {
125	                found: describe_kind(&self.tokens[self.pos].kind),
126	                span: self.tokens[self.pos].span,
127	            })
128	        }
129	    }
