131	    /// Parse an expression with precedence climbing (min_prec=0 for full expr).
132	    pub(crate) fn parse_expr(&mut self, min_prec: u8) -> Result<Expr, ParseError> {
133	        let mut lhs = self.parse_atom()?;
134	        loop {
135	            let Some((op, prec)) = self.tokens.get(self.pos).and_then(|t| match t.kind {
136	                TokenKind::Plus => Some((BinOpKind::Add, 1u8)),
137	                TokenKind::Minus => Some((BinOpKind::Sub, 1)),
138	                TokenKind::Star => Some((BinOpKind::Mul, 2)),
139	                TokenKind::Slash => Some((BinOpKind::Div, 2)),
140	                _ => None,
141	            }) else {
142	                break;
143	            };
144	            if prec < min_prec {
145	                break;
146	            }
147	            self.pos += 1;
148	            let rhs = self.parse_expr(prec + 1)?;
149	            let span = Span::new(lhs.span().start, rhs.span().end);
