12	pub(crate) fn eval_binop(
13	    op: &BinOpKind,
14	    lhs: &Expr,
15	    rhs: &Expr,
16	    env: &mut Environment,
17	    trace: &mut Option<&mut Trace>,
18	) -> Result<(&'static str, Vec<TraceValue>, DenseArray), EvalError> {
19	    let l = eval_expr(lhs, env, trace)?.into_array()?;
20	    let r = eval_expr(rhs, env, trace)?.into_array()?;
21	    let (name, f): (&str, fn(f64, f64) -> f64) = match op {
22	        BinOpKind::Add => ("add", |a, b| a + b),
23	        BinOpKind::Sub => ("sub", |a, b| a - b),
24	        BinOpKind::Mul => ("mul", |a, b| a * b),
25	        BinOpKind::Div => ("div", |a, b| a / b),
26	    };
27	    let inputs = vec![TraceValue::from_array(&l), TraceValue::from_array(&r)];
28	    let result = l.apply_binop(&r, f)?;
29	    Ok((name, inputs, result))
