47	pub(crate) fn eval_svg(
48	    args: &[Expr],
49	    env: &mut Environment,
50	    trace: &mut Option<&mut Trace>,
51	) -> Result<String, EvalError> {
52	    if args.len() != 2 && args.len() != 3 {
53	        return Err(EvalError::BadArity {
54	            func: "svg".into(),
55	            expected: 2,
56	            got: args.len(),
57	        });
58	    }
59	    let data = eval_expr(&args[0], env, trace)?.into_array()?;
60	    let type_name = match eval_expr(&args[1], env, trace)? {
61	        Value::Str(s) => s,
62	        Value::Array(_) | Value::Model(_) => return Err(EvalError::ExpectedString),
63	    };
64	    let aux = if args.len() == 3 {
65	        Some(eval_expr(&args[2], env, trace)?.into_array()?)
66	    } else {
67	        None
68	    };
69	    Ok(mlpl_viz::render_with_aux(&data, &type_name, aux.as_ref())?)
