72	/// Dispatch high-level analysis helpers from `mlpl_viz`. Returns
73	/// `None` if `name` is not a known helper.
74	pub(crate) fn eval_analysis_helper(
75	    name: &str,
76	    args: &[Expr],
77	    env: &mut Environment,
78	    trace: &mut Option<&mut Trace>,
79	) -> Option<Result<String, EvalError>> {
80	    if !matches!(
81	        name,
82	        "hist" | "scatter_labeled" | "loss_curve" | "confusion_matrix" | "boundary_2d"
83	    ) {
84	        return None;
85	    }
86	    let evaluated: Result<Vec<DenseArray>, EvalError> = args
87	        .iter()
88	        .map(|a| eval_expr(a, env, trace).and_then(Value::into_array))
89	        .collect();
90	    Some(match evaluated {
91	        Ok(arrs) => call_analysis(name, &arrs),
92	        Err(e) => Err(e),
93	    })
94	}
95	
96	fn call_analysis(name: &str, a: &[DenseArray]) -> Result<String, EvalError> {
97	    let bad_arity = |expected: usize| EvalError::BadArity {
98	        func: name.into(),
99	        expected,
100	        got: a.len(),
101	    };
102	    Ok(match name {
103	        "hist" => {
104	            if a.len() != 2 {
105	                return Err(bad_arity(2));
106	            }
107	            if a[1].rank() != 0 {
108	                return Err(EvalError::ExpectedString);
109	            }
110	            mlpl_viz::analysis_hist(&a[0], a[1].data()[0] as usize)?
111	        }
112	        "scatter_labeled" => {
113	            if a.len() != 2 {
114	                return Err(bad_arity(2));
115	            }
116	            mlpl_viz::analysis_scatter_labeled(&a[0], &a[1])?
117	        }
118	        "loss_curve" => {
119	            if a.len() != 1 {
120	                return Err(bad_arity(1));
121	            }
122	            mlpl_viz::analysis_loss_curve(&a[0])?
123	        }
124	        "confusion_matrix" => {
125	            if a.len() != 2 {
126	                return Err(bad_arity(2));
127	            }
128	            mlpl_viz::analysis_confusion_matrix(&a[0], &a[1])?
129	        }
130	        "boundary_2d" => {
131	            if a.len() != 4 {
132	                return Err(bad_arity(4));
133	            }
134	            mlpl_viz::analysis_boundary_2d(&a[0], &a[1], &a[2], &a[3])?
135	        }
136	        _ => unreachable!(),
137	    })
138	}
139	
140	pub(crate) fn eval_array_lit(
141	    elems: &[Expr],
142	    env: &mut Environment,
143	    trace: &mut Option<&mut Trace>,
144	) -> Result<DenseArray, EvalError> {
145	    if elems.is_empty() {
146	        return Ok(DenseArray::from_vec(vec![]));
147	    }
148	    let evaluated: Vec<DenseArray> = elems
149	        .iter()
150	        .map(|e| eval_expr(e, env, trace).and_then(Value::into_array))
151	        .collect::<Result<Vec<_>, _>>()?;
152	    if evaluated.iter().all(|a| a.rank() == 0) {
153	        let data: Vec<f64> = evaluated.iter().map(|a| a.data()[0]).collect();
154	        return Ok(DenseArray::from_vec(data));
155	    }
156	    let inner_shape = evaluated[0].shape().clone();
157	    let rows = evaluated.len();
158	    let mut data = Vec::with_capacity(rows * inner_shape.elem_count());
159	    for arr in &evaluated {
160	        data.extend_from_slice(arr.data());
161	    }
162	    let mut dims = vec![rows];
163	    dims.extend_from_slice(inner_shape.dims());
164	    Ok(DenseArray::new(Shape::new(dims), data)?)
165	}
