19	fn builtin_softmax(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
20	    if args.len() != 2 {
21	        return Err(RuntimeError::ArityMismatch {
22	            func: name.into(),
23	            expected: 2,
24	            got: args.len(),
25	        });
26	    }
27	    if args[1].rank() != 0 {
28	        return Err(RuntimeError::InvalidArgument {
29	            func: name.into(),
30	            reason: format!("axis must be scalar, got rank {}", args[1].rank()),
31	        });
32	    }
33	    let a = &args[0];
34	    let axis = args[1].data()[0] as usize;
35	    let dims = a.shape().dims().to_vec();
36	    if axis >= dims.len() {
37	        return Err(RuntimeError::InvalidArgument {
38	            func: name.into(),
39	            reason: format!("axis {axis} out of range for rank {}", dims.len()),
40	        });
41	    }
42	
43	    // Strides for the input shape.
44	    let mut strides = vec![1usize; dims.len()];
45	    for i in (0..dims.len().saturating_sub(1)).rev() {
46	        strides[i] = strides[i + 1] * dims[i + 1];
47	    }
48	    let axis_size = dims[axis];
49	    let axis_stride = strides[axis];
50	
51	    // Group index: flat index with the `axis` coordinate removed.
52	    let mut group_dims = dims.clone();
53	    group_dims.remove(axis);
54	    let group_count: usize = group_dims.iter().product::<usize>().max(1);
55	
56	    // First pass: per-group max for numerical stability.
57	    let mut maxv = vec![f64::NEG_INFINITY; group_count];
58	    for flat in 0..a.elem_count() {
59	        let g = if axis_stride > 1 {
60	            let outer = flat / (axis_size * axis_stride);
61	            let inner = flat % axis_stride;
62	            outer * axis_stride + inner
63	        } else {
64	            flat / axis_size
65	        };
66	        let v = a.data()[flat];
67	        if v > maxv[g] {
68	            maxv[g] = v;
69	        }
70	    }
71	
72	    // Second pass: exponentiate shifted logits and accumulate per-group sums.
73	    let mut out = vec![0.0f64; a.elem_count()];
74	    let mut sums = vec![0.0f64; group_count];
75	    for (flat, slot) in out.iter_mut().enumerate() {
76	        let g = if axis_stride > 1 {
77	            let outer = flat / (axis_size * axis_stride);
78	            let inner = flat % axis_stride;
79	            outer * axis_stride + inner
80	        } else {
81	            flat / axis_size
82	        };
83	        let e = (a.data()[flat] - maxv[g]).exp();
84	        *slot = e;
85	        sums[g] += e;
86	    }
87	
88	    // Third pass: normalize.
89	    for (flat, slot) in out.iter_mut().enumerate() {
90	        let g = if axis_stride > 1 {
91	            let outer = flat / (axis_size * axis_stride);
92	            let inner = flat % axis_stride;
93	            outer * axis_stride + inner
94	        } else {
95	            flat / axis_size
96	        };
97	        *slot /= sums[g];
98	    }
99	
100	    Ok(DenseArray::new(Shape::new(dims), out)?)
101	}
