//! Evaluation helpers for binops, function calls, and array literals.

use mlpl_array::{ArrayError, DenseArray, Shape};
use mlpl_core::LabeledShape;
use mlpl_parser::{BinOpKind, Expr};
use mlpl_trace::{Trace, TraceValue};

use crate::env::Environment;
use crate::error::EvalError;
use crate::eval::eval_expr;
use crate::value::Value;

pub(crate) fn eval_binop(
    op: &BinOpKind,
    lhs: &Expr,
    rhs: &Expr,
    env: &mut Environment,
    trace: &mut Option<&mut Trace>,
) -> Result<(&'static str, Vec<TraceValue>, DenseArray), EvalError> {
    let l = eval_expr(lhs, env, trace)?.into_array()?;
    let r = eval_expr(rhs, env, trace)?.into_array()?;
    let (name, f): (&str, fn(f64, f64) -> f64) = match op {
        BinOpKind::Add => ("add", |a, b| a + b),
        BinOpKind::Sub => ("sub", |a, b| a - b),
        BinOpKind::Mul => ("mul", |a, b| a * b),
        BinOpKind::Div => ("div", |a, b| a / b),
    };
    let inputs = vec![TraceValue::from_array(&l), TraceValue::from_array(&r)];
    let result = match l.apply_binop(&r, f) {
        Ok(a) => a,
        Err(e @ (ArrayError::ShapeMismatch { .. } | ArrayError::LabelMismatch { .. })) => {
            return Err(shape_mismatch(name, &l, &r, e));
        }
        Err(e) => return Err(e.into()),
    };
    Ok((name, inputs, result))
}

/// Build an `EvalError::ShapeMismatch` from two operands and their
/// triggering array-layer error. Used by elementwise and matmul paths
/// to lift `ArrayError::ShapeMismatch` / `LabelMismatch` into a richer
/// evaluator-level error that names the op and carries both labeled
/// shapes. Saga 11.5 Phase 4.
pub(crate) fn shape_mismatch(
    op: &str,
    l: &DenseArray,
    r: &DenseArray,
    _cause: ArrayError,
) -> EvalError {
    EvalError::ShapeMismatch {
        op: op.into(),
        expected: labeled_shape_of(l),
        actual: labeled_shape_of(r),
    }
}

/// Snapshot an array's dims + label list as a `LabeledShape`. Unlabeled
/// arrays get `None` at every axis.
pub(crate) fn labeled_shape_of(a: &DenseArray) -> LabeledShape {
    let labels = a
        .labels()
        .map_or_else(|| vec![None; a.rank()], <[_]>::to_vec);
    LabeledShape::new(a.shape().dims().to_vec(), labels)
}

